-- Repair v3 template responses IN PLACE (ids stable). The old rows carried
-- round-robin BUY/SELL text unconditioned on the profile, LaTeX artifacts,
-- and no emotional_arc. This rewrite derives everything from the joined
-- profile's own traits/factors and the scenario's category, with md5(id)
-- variation — the same composition logic as scripts/lib/behavior.js.
-- Idempotent: the junk-text predicate no longer matches after the rewrite.

UPDATE profile_scenario_responses r SET
  response = (CASE WHEN mod((('x'||substr(md5(r.id::text||'ot'),1,8))::bit(32)::int & 2147483647), 10) < 6
      THEN (ARRAY['Faced with','Confronted with','Dropped into','Hit with']::text[])[1 + mod((('x'||substr(md5(r.id::text||'op'),1,8))::bit(32)::int & 2147483647), 4)] || ' "' || lower(regexp_replace(s.title, '\s*\(.*\)$', '')) || '"'
      ELSE (ARRAY['Faced with this','Put in this spot','Confronted with it','Dropped into this','When it lands on their desk','In the moment']::text[])[1 + mod((('x'||substr(md5(r.id::text||'op'),1,8))::bit(32)::int & 2147483647), 6)] END) || ', this '
             || replace(COALESCE(p.content->>'archetype', 'trader'), '-', ' ') || ' '
             || (CASE s.category
      WHEN 'trading' THEN CASE calc.bucket WHEN 'cautious' THEN (b.a_tr_cau)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'calculating' THEN (b.a_tr_cal)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'bold' THEN (b.a_tr_bol)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'impulsive' THEN (b.a_tr_imp)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] END
      WHEN 'negotiation' THEN CASE calc.bucket WHEN 'cautious' THEN (b.a_ne_cau)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'calculating' THEN (b.a_ne_cal)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'bold' THEN (b.a_ne_bol)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'impulsive' THEN (b.a_ne_imp)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] END
      WHEN 'social' THEN CASE calc.bucket WHEN 'cautious' THEN (b.a_so_cau)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'calculating' THEN (b.a_so_cal)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'bold' THEN (b.a_so_bol)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'impulsive' THEN (b.a_so_imp)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] END
      WHEN 'crisis' THEN CASE calc.bucket WHEN 'cautious' THEN (b.a_cr_cau)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'calculating' THEN (b.a_cr_cal)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'bold' THEN (b.a_cr_bol)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'impulsive' THEN (b.a_cr_imp)[1 + mod((('x'||substr(md5(r.id::text||'ac'),1,8))::bit(32)::int & 2147483647), 6)] END
      END)
             || (CASE p.content->'suggested_biases'->0->>'slug'
      WHEN 'loss-aversion' THEN ', and true to form ' || (ARRAY['guards against losses far more fiercely than they chase equivalent gains','feels a loss twice as sharply as an equivalent gain and plans accordingly','will give up a good bet just to avoid the chance of a bad one','keeps the insurance mindset even in situations that reward the lottery mindset']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'fomo' THEN ', and true to form ' || (ARRAY['jumps into whatever everyone else already seems to be winning at','cannot watch a rally from the sidelines for long','treats being left out of a move as its own kind of loss','hears about a closed door and immediately needs to be on the other side of it']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'anchoring' THEN ', and true to form ' || (ARRAY['lets the first number on the table quietly set the whole range','never quite escapes the first figure it heard, however arbitrary','measures every later offer against the opening one, not against fair value','negotiates with the sticker price long after everyone agreed it was fiction']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'sunk-cost' THEN ', and true to form ' || (ARRAY['throws good effort after bad to justify the effort already spent','keeps paying into something mainly because of what has already been paid','treats walking away as wasting the investment rather than stopping the bleeding','finishes bad books, bad meals, and bad trades on the same principle']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'confirmation' THEN ', and true to form ' || (ARRAY['hunts for evidence that agrees with them and files the rest under noise','reads disagreement as a data error rather than new information','remembers the sources that agreed with it better than the ones that did not','asks questions shaped exactly like the answers it wants']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'overconfidence' THEN ', and true to form ' || (ARRAY['holds their estimates with a certainty the track record does not support','is more certain than the hit rate justifies','underestimates how often an obviously right call turns out wrong','budgets no room for the version of events where it is simply wrong']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'herd-behavior' THEN ', and true to form ' || (ARRAY['abandons a private read the instant the crowd leans the other way','finds it hard to hold a contrarian position once the room disagrees','takes the crowd''s confidence as a substitute for its own analysis','checks what everyone else did before checking what the situation calls for']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'availability' THEN ', and true to form ' || (ARRAY['weights whatever happened most recently and vividly as if it were typical','judges likelihood by how easily an example comes to mind, not by the base rate','overweights the vivid story over the boring statistic every time','prices the risk by the story it heard last week, not the table it saw last year']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'recency' THEN ', and true to form ' || (ARRAY['extrapolates the last data point into a permanent trend','assumes the current streak is the new normal','discounts the older pattern in favor of whatever just happened','treats the last three data points as a trend and the previous thirty as history']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'disposition-effect' THEN ', and true to form ' || (ARRAY['sells the winners early and clings to the losers for far too long','locks in small wins fast and rides large losses far past the point of sense','feels a winning position as fragile and a losing one as merely paused','banks the small win by reflex and babysits the large loss on principle']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'status-quo' THEN ', and true to form ' || (ARRAY['defends the current arrangement as if change itself were the danger','needs a change to clear a higher bar than staying put ever has to','treats the default option as the safe one by default, not by analysis','renews by default and renegotiates never']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'endowment' THEN ', and true to form ' || (ARRAY['overvalues whatever they already hold simply because it is theirs','would not buy back what it already owns at the price it would sell it for','feels parting with something as a bigger loss than its market value explains','prices its own things with a premium called familiarity']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'hindsight' THEN ', and true to form ' || (ARRAY['remembers every surprise as something they saw coming all along','rewrites its own uncertainty out of the story after the fact','is surprised in the moment and certain in the retelling','narrates last month''s coin flip as last month''s obvious call']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'optimism' THEN ', and true to form ' || (ARRAY['discounts their own exposure to the risks they warn others about','assumes the bad statistic applies to other people','expects to be the exception to a risk it can otherwise describe accurately','plans for the median outcome and is repeatedly surprised by the distribution']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'framing' THEN ', and true to form ' || (ARRAY['flips their choice depending purely on how the option is worded','answers differently depending on whether the same fact is framed as a gain or a loss','is swayed by which number comes first, not just what the numbers mean','buys the 90-percent-fat-free version of the exact same decision']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'gamblers-fallacy' THEN ', and true to form ' || (ARRAY['expects the streak to reverse in games that never remember the past','feels a losing streak owes it a win','treats independent events as if they were keeping score','counts the reds and bets the black, in markets with no wheel']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'ostrich-effect' THEN ', and true to form ' || (ARRAY['looks away from bad news in the hope it resolves unwitnessed','delays checking the number it most needs to check','would rather not know yet, even when knowing sooner would help','schedules the difficult look-at-the-numbers for a tomorrow that keeps moving']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'bandwagon' THEN ', and true to form ' || (ARRAY['adopts a conviction mainly because the room already has','gains confidence in a position in proportion to how many others hold it','finds it easier to believe something once it stops being a minority view','finds an idea twice as convincing once it comes with a crowd attached']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'authority-bias' THEN ', and true to form ' || (ARRAY['defers to the most senior voice even against their own evidence','gives a credentialed opinion more weight than the argument earns','second-guesses its own read the moment someone senior disagrees','hears the title before the argument and weights accordingly']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      WHEN 'dunning-kruger' THEN ', and true to form ' || (ARRAY['is most certain precisely where their competence is thinnest','cannot see the gap in its own knowledge from inside the gap','mistakes a little fluency for real mastery','speaks longest on the topics it has read least about']::text[])[1 + mod((('x'||substr(md5(r.id::text||'qk'),1,8))::bit(32)::int & 2147483647), 4)]
      ELSE '' END) || '.',
  reasoning_chain = (CASE COALESCE(p.decision_style, 'analytical')
      WHEN 'analytical' THEN (b.re_anal)[1 + mod((('x'||substr(md5(r.id::text||'re'),1,8))::bit(32)::int & 2147483647), 8)]
      WHEN 'intuitive' THEN (b.re_intu)[1 + mod((('x'||substr(md5(r.id::text||'re'),1,8))::bit(32)::int & 2147483647), 8)]
      WHEN 'dependent' THEN (b.re_depe)[1 + mod((('x'||substr(md5(r.id::text||'re'),1,8))::bit(32)::int & 2147483647), 8)]
      WHEN 'avoidant' THEN (b.re_avoi)[1 + mod((('x'||substr(md5(r.id::text||'re'),1,8))::bit(32)::int & 2147483647), 8)]
      WHEN 'spontaneous' THEN (b.re_spon)[1 + mod((('x'||substr(md5(r.id::text||'re'),1,8))::bit(32)::int & 2147483647), 8)]
      WHEN 'deliberative' THEN (b.re_deli)[1 + mod((('x'||substr(md5(r.id::text||'re'),1,8))::bit(32)::int & 2147483647), 8)]
      ELSE (b.re_anal)[1 + mod((('x'||substr(md5(r.id::text||'re'),1,8))::bit(32)::int & 2147483647), 8)] END) || ' ' || (CASE s.category
      WHEN 'trading' THEN (b.cx_tr)[1 + mod((('x'||substr(md5(r.id::text||'cx'),1,8))::bit(32)::int & 2147483647), 5)]
      WHEN 'negotiation' THEN (b.cx_ne)[1 + mod((('x'||substr(md5(r.id::text||'cx'),1,8))::bit(32)::int & 2147483647), 5)]
      WHEN 'social' THEN (b.cx_so)[1 + mod((('x'||substr(md5(r.id::text||'cx'),1,8))::bit(32)::int & 2147483647), 5)]
      WHEN 'crisis' THEN (b.cx_cr)[1 + mod((('x'||substr(md5(r.id::text||'cx'),1,8))::bit(32)::int & 2147483647), 5)]
      END),
  emotional_arc = (upper(left((CASE calc.nb WHEN 'high' THEN (b.op_high)[1 + mod((('x'||substr(md5(r.id::text||'op'),1,8))::bit(32)::int & 2147483647), 7)] WHEN 'mid' THEN (b.op_mid)[1 + mod((('x'||substr(md5(r.id::text||'op'),1,8))::bit(32)::int & 2147483647), 7)] WHEN 'low' THEN (b.op_low)[1 + mod((('x'||substr(md5(r.id::text||'op'),1,8))::bit(32)::int & 2147483647), 7)] END),1)) || substr((CASE calc.nb WHEN 'high' THEN (b.op_high)[1 + mod((('x'||substr(md5(r.id::text||'op'),1,8))::bit(32)::int & 2147483647), 7)] WHEN 'mid' THEN (b.op_mid)[1 + mod((('x'||substr(md5(r.id::text||'op'),1,8))::bit(32)::int & 2147483647), 7)] WHEN 'low' THEN (b.op_low)[1 + mod((('x'||substr(md5(r.id::text||'op'),1,8))::bit(32)::int & 2147483647), 7)] END),2)) || ', resolving into ' || (CASE calc.nb WHEN 'high' THEN (b.pa_high)[1 + mod((('x'||substr(md5(r.id::text||'pa'),1,8))::bit(32)::int & 2147483647), 7)] WHEN 'mid' THEN (b.pa_mid)[1 + mod((('x'||substr(md5(r.id::text||'pa'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'low' THEN (b.pa_low)[1 + mod((('x'||substr(md5(r.id::text||'pa'),1,8))::bit(32)::int & 2147483647), 5)] END)
                  || ' — ' || (CASE calc.nb WHEN 'high' THEN (b.cl_high)[1 + mod((('x'||substr(md5(r.id::text||'cl'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'mid' THEN (b.cl_mid)[1 + mod((('x'||substr(md5(r.id::text||'cl'),1,8))::bit(32)::int & 2147483647), 6)] WHEN 'low' THEN (b.cl_low)[1 + mod((('x'||substr(md5(r.id::text||'cl'),1,8))::bit(32)::int & 2147483647), 6)] END) || '.',
  confidence = round((LEAST(0.98, GREATEST(0.15, 0.40 + 0.25*(1 - p.neuroticism) + 0.15*p.conscientiousness
     + CASE WHEN p.content->'suggested_biases'->0->>'slug' = 'overconfidence' THEN 0.15 ELSE 0 END
     + 0.015*COALESCE((p.content->'cognitive_reflection'->>'crt_score')::numeric, 1)
     - CASE WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0) >= 2.5
             AND s.category IN ('trading','crisis') THEN 0.05 ELSE 0 END
     + CASE WHEN (p.content->'dark_triad'->>'psychopathy')::numeric > 0.6 THEN 0.04 ELSE 0 END
     + CASE WHEN (p.content->'dark_triad'->>'narcissism')::numeric > 0.65 THEN 0.04 ELSE 0 END
     + (((('x'||substr(md5(r.id::text||'cf'),1,8))::bit(32)::int & 2147483647)::numeric / 2147483647.0) - 0.5)*0.10)))::numeric, 2)
FROM profiles p, scenarios s,
LATERAL (SELECT
    CASE WHEN (0.5*(1 - p.neuroticism) + 0.3*p.openness + 0.2*(1 - p.agreeableness)
               + 0.10 - 0.06*LEAST(3.6, GREATEST(0.6, COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0)))
               + CASE WHEN (p.content->'dark_triad'->>'psychopathy')::numeric > 0.6 THEN 0.06 ELSE 0 END) >= 0.55
         THEN CASE WHEN (0.6*(1 - p.conscientiousness) + 0.4*p.extraversion
                         + CASE WHEN p.content->'cognitive_reflection'->>'system_preference' = 'system1' THEN 0.05 ELSE 0 END
                         - 0.03*LEAST(3, COALESCE((p.content->'cognitive_reflection'->>'crt_score')::numeric, 1))) >= 0.5
                   THEN 'bold' ELSE 'calculating' END
         ELSE CASE WHEN (0.6*(1 - p.conscientiousness) + 0.4*p.extraversion
                         + CASE WHEN p.content->'cognitive_reflection'->>'system_preference' = 'system1' THEN 0.05 ELSE 0 END
                         - 0.03*LEAST(3, COALESCE((p.content->'cognitive_reflection'->>'crt_score')::numeric, 1))) >= 0.5
                   THEN 'impulsive' ELSE 'cautious' END
    END AS bucket,
    CASE WHEN p.neuroticism >= 0.65 THEN 'high' WHEN p.neuroticism <= 0.35 THEN 'low' ELSE 'mid' END AS nb
  ) calc,
(SELECT
  ARRAY['cuts risk immediately, banking safety over upside and accepting a worse price to sleep at night','trims the position in stages, prioritizing capital preservation over any residual upside','exits into the first available liquidity rather than waiting for a better print','de-risks well before the textbook signal, uncomfortable holding exposure into the unknown','halves the position twice rather than deciding once, buying certainty in installments','parks the proceeds in the safest thing on the screen and revisits when the tape calms down']::text[] AS a_tr_cau,
  ARRAY['sizes the decision off a pre-set rule, ignoring the noise and executing the plan mechanically','runs the scenario through a checklist built in advance and follows wherever it points','treats the moment as one more data point for a system, not an exception to react to','executes the pre-committed plan exactly, resisting the urge to improvise under pressure','re-reads the written playbook aloud before touching the keyboard, then does what it says','sizes the response to the signal, not the feeling, and logs both for the review']::text[] AS a_tr_cal,
  ARRAY['leans into the move, adding exposure where others are flinching and betting on the reversal','presses the position further, treating the volatility itself as the opportunity','takes the contrarian side deliberately, willing to be early and wrong before being right','scales in aggressively, judging the crowd''s fear as the better signal to fade','sells the calm and buys the panic on the theory that emotion is the only mispriced asset left','widens the mandate on the spot, treating the dislocation as the opportunity the plan never imagined']::text[] AS a_tr_bol,
  ARRAY['acts on the first strong feeling, hitting the button before the reasoning fully forms','chases the move in real time, adjusting size on gut feel as the price ticks','reacts to the headline before confirming it, then scrambles to justify the trade after','flips the position on a hunch mid-session without waiting for confirmation','market-orders first and calculates the size it should have been afterward','reacts to the candle, not the cause, and is fully repositioned before the news is even confirmed']::text[] AS a_tr_imp,
  ARRAY['protects the relationship, conceding ground to keep the deal and the goodwill intact','softens the ask to keep the conversation moving rather than risk a stall','offers a face-saving off-ramp for the other side even at some cost to itself','prioritizes a durable outcome over a maximal one','trades the last dollar on the table for the first call answered next time','bends on the number to hold the terms that actually compound']::text[] AS a_ne_cau,
  ARRAY['holds the line to their BATNA, trading patience for leverage and refusing to move first','lets the numbers set the floor and refuses to negotiate against itself','tracks concessions explicitly and matches them one-for-one, never more','stays silent past the point of discomfort, letting the other side fill the gap','restates the other side''s position better than they did, then lets the asymmetry do the work','moves only when a concession can be traded, never merely given']::text[] AS a_ne_cal,
  ARRAY['counters aggressively, re-anchoring hard and daring the other side to walk','sets an ultimatum earlier than convention allows, betting the other side blinks first','walks from the table on principle, trusting the other side to come back','pushes for the full ask, treating a bruised relationship as an acceptable cost','re-anchors above the original ask, converting their tactic into the new baseline','introduces a competing suitor, real enough, and lets scarcity renegotiate']::text[] AS a_ne_bol,
  ARRAY['blurts a number or an ultimatum, then has to live with wherever it lands','agrees on the spot to end the tension, details to be sorted out later','escalates the demand mid-conversation on impulse, surprising even itself','accepts the first workable offer rather than sit with more back-and-forth','gives away a real concession to end the meeting, then spends the week justifying it','names a final number mid-sentence and is as surprised as anyone that it holds']::text[] AS a_ne_imp,
  ARRAY['smooths it over, absorbing the discomfort to keep the peace even at personal cost','steps back and lets the moment pass rather than force a resolution','chooses the gentlest true version of events available','defers the confrontation to a calmer, more private moment','lets the moment cool exactly one day, then addresses it in the smallest possible room','absorbs the jab in public and files it privately under things that will matter later']::text[] AS a_so_cau,
  ARRAY['responds deliberately, choosing words to protect their standing without escalating','reads the room fully before committing to a position','frames the response so it can be walked back later if needed','weighs the audience as carefully as the actual disagreement','answers the reasonable version of the attack and leaves the unreasonable version unclaimed','asks one precise question that makes the room do the confronting instead']::text[] AS a_so_cal,
  ARRAY['confronts it head-on, naming the problem in the room regardless of who bristles','calls it out publicly rather than let it pass unaddressed','takes the harder, more direct route on principle','draws the line clearly, accepting the social cost as the price of clarity','names the behavior, not the person, and does it while everyone is still watching','spends social capital on the spot, on principle, without checking the balance first']::text[] AS a_so_bol,
  ARRAY['reacts in the moment, saying the thing everyone was thinking and dealing with fallout later','fires back before fully thinking it through','lets the first reaction show on their face and in their words','responds in the heat of it, unfiltered','says the quiet part at full volume and lets the fallout schedule itself','laughs at the wrong moment, honestly, and deals with what that reveals']::text[] AS a_so_imp,
  ARRAY['follows protocol to the letter, escalating up the chain rather than acting alone','waits for authorization even when it costs time, unwilling to freelance the response','documents before acting, wary of a decision it cannot later justify','defers the riskiest calls to whoever has the formal authority to make them','keeps a written timeline from minute one so every later question has a boring answer','slows the room down on purpose, trading minutes of delay for hours of rework avoided']::text[] AS a_cr_cau,
  ARRAY['triages coldly, sequencing the least-reversible decisions first and documenting each step','builds a rapid decision tree and works it in order, ignoring the noise around it','isolates the irreversible choices and makes those first, deferring the rest','treats the incident as a sequence of small decisions rather than one big one','freezes the blast radius first and only then starts diagnosing the cause','assigns one owner per unknown and reconvenes on a timer instead of on emotion']::text[] AS a_cr_cal,
  ARRAY['takes command and acts decisively, accepting personal risk to move faster than the situation','makes the call alone rather than wait for consensus that will not arrive in time','moves first and briefs everyone else after, betting speed matters more than buy-in','accepts blame in advance in exchange for the authority to act now','declares the emergency before anyone else will, and owns the false-alarm risk out loud','spends reputation to buy speed, on the theory that reputations recover and outages compound']::text[] AS a_cr_bol,
  ARRAY['lunges at the most visible fix, trading a fast intervention for a considered one','acts on the first plausible fix without checking for a better one','reacts to the loudest signal in the room rather than the most important one','moves before the full picture is in, unable to tolerate the uncertainty','fixes the loudest symptom first, which is occasionally even the actual problem','declares a direction to end the meeting, then quietly reverses half of it by morning']::text[] AS a_cr_imp,
  ARRAY['Lays out the options explicitly, assigns each a rough expected value, and picks the one that survives the numbers — distrusting any impulse that cannot be written down.','Breaks the decision into weighted criteria before looking at gut feel, and lets the tally overrule any single strong reaction.','Treats the choice as a small research problem: gather the knowable facts first, model the downside, then commit only once the math stops moving.','Distrusts the first plausible-sounding answer and keeps testing alternatives until one survives every objection raised against it.','Builds an explicit decision matrix for a call most people would make on instinct, and defers to whichever option scores highest even if it feels wrong.','Separates the emotional read from the analytical one on purpose, writes both down, and lets the analytical read win the tiebreak.','Prices the reversible and irreversible parts of the choice separately, and spends its caution almost entirely on the second.','Asks what the calmest competent person it knows would do, then checks that answer against the numbers before borrowing it.']::text[] AS re_anal,
  ARRAY['Reads the situation in a single gut pass, locks onto the option that "feels" right, and assembles the justification afterward.','Trusts a felt sense of pattern over any spreadsheet, treating hesitation itself as evidence something is off.','Recognizes the shape of the situation from past experience before consciously naming why, then acts on that recognition.','Skips the formal weighing entirely — the answer arrives whole, and the reasoning is reconstructed only if someone asks for it.','Lets a fast, holistic read override any slower counting of pros and cons that might contradict it.','Feels the decision settle before it is fully articulated, and moves on that settling rather than waiting for certainty.','Notices which option it keeps defending in imaginary arguments, and takes that as the verdict already rendered.','Reads the first ten seconds of its own reaction as the highest-quality data in the room.']::text[] AS re_intu,
  ARRAY['Mentally polls trusted voices and prior authority before committing, reluctant to own the call alone.','Delays a final answer until at least one credible outside opinion has weighed in, treating solo conviction as insufficient.','Looks for precedent or a mentor''s read before trusting its own judgment on something this consequential.','Frames the decision as something to be validated rather than made, and keeps circling until someone else signs off.','Weighs its own instinct as only one input among several trusted others, and defers when they disagree.','Feels most confident the moment someone with more authority confirms the direction, and shaky right up until then.','Rehearses how the decision will be explained to the people it answers to, and picks the option with the sturdiest explanation.','Treats consensus as a safety feature, not a shortcut — the point is to never be wrong alone.']::text[] AS re_depe,
  ARRAY['Searches first for a way to not decide — a delay, a deferral, a partial step — and only acts when forced.','Treats not-choosing as a safe choice right up until the option closes on its own.','Buries the hard call under a pile of preparatory busywork that never quite finishes.','Looks for a reason the decision belongs to someone else, or to a later date, before considering it directly.','Keeps every option notionally open as long as possible, even at the cost of the best ones expiring first.','Reframes inaction as patience, and patience as strategy, for as long as the situation allows.','Breaks the decision into stages mostly so the committing stage can be scheduled for later.','Gathers one more opinion not to learn from it but to postpone the moment the choice becomes its own.']::text[] AS re_avoi,
  ARRAY['Commits fast to end the tension, treating a quick wrong move as better than a slow right one.','Acts on the strongest immediate impulse and treats hesitation as its own kind of risk.','Picks the option that resolves the discomfort of choosing fastest, then adapts to whatever follows.','Trusts the first workable idea enough to move on it before a second one can compete for attention.','Prefers a decisive wrong turn to an open-ended maybe, and corrects course later if it has to.','Lets urgency substitute for analysis, converting pressure directly into action.','Counts any decision made today as beating a better one made next week, and acts accordingly.','Trusts that motion generates information no amount of stillness will, and buys that information immediately.']::text[] AS re_spon,
  ARRAY['Walks every branch and contingency in sequence, uneasy until the residual ambiguity is as small as it can be.','Slow-walks the decision through every foreseeable consequence before allowing itself to commit.','Treats a rushed decision as a defect regardless of outcome, and resists pressure to shortcut the process.','Keeps expanding the list of scenarios to consider until diminishing returns finally force a stop.','Wants the decision to survive hindsight, not just produce a good outcome, so it over-invests in the reasoning itself.','Revisits the same decision from a new angle each time doubt resurfaces, even after nominally deciding.','Interrogates the option it likes hardest, on the theory that preference is where the errors hide.','Maps who is harmed under each branch before asking who benefits, and lets the downside map drive.']::text[] AS re_deli,
  ARRAY['This time the variable is money moving in real time.','The numbers on the screen are the only feedback that matters here.','Price action does not care which argument feels more convincing.','Liquidity, not conviction, decides what an exit is worth here.','Being early and being wrong settle to the same P&L today.']::text[] AS cx_tr,
  ARRAY['The counterparty is reading every hesitation as information.','Every option here also has to survive the other side''s reaction.','The relationship and the number are both on the table at once.','Whatever gets conceded here becomes the precedent for the next three asks.','The other side is pricing your patience as carefully as your position.']::text[] AS cx_ne,
  ARRAY['An audience is watching how this gets handled.','Whatever happens next becomes part of the story people tell about it.','The social cost and the practical cost point in different directions.','Everyone watching will remember the tone longer than the substance.','The relationship will outlast whatever this disagreement is nominally about.']::text[] AS cx_so,
  ARRAY['There is no version of this where every stakeholder ends up satisfied.','The clock is compressing a decision that would normally take longer.','Getting this wrong in public is worse than getting it wrong quietly.','Half the damage here is the decision; the other half is how the decision travels.','Every hour of delay closes some options and quietly reprices the rest.']::text[] AS cx_cr,
  ARRAY['A sharp initial spike of dread','An immediate jolt of alarm','A rush of adrenaline that narrows focus fast','A hot flash of panic before any thought forms','An instant lurch in the stomach','A cold drop, like a floor giving way half an inch','A surge of alarm that arrives before the details do']::text[] AS op_high,
  ARRAY['that lingers and colors the aftermath long after the moment passes','that keeps resurfacing in quiet moments for days afterward','that leaves a residue of vigilance well past the event itself','that gets relived and replayed long after it stops being useful','that keeps the hands slightly unsteady well into the next task','that outlives the event and starts coloring unrelated decisions']::text[] AS cl_high,
  ARRAY['panic selling','paralysis','anxious spiral','dissociative deferral','guilt absorption','fomo buying','aggressive counter']::text[] AS pa_high,
  ARRAY['A brief flicker of tension','A noticeable but manageable spike of unease','A quick surge of adrenaline that fades as fast as it came','A momentary tightening before the response settles','A flash of heat that cools almost immediately','A held breath that lets itself out halfway','An alert, coiled attention with no panic in it yet']::text[] AS op_mid,
  ARRAY['that settles once the choice is made','that fades within the hour once the decision is locked in','that resolves as soon as there is something concrete to act on','that dissolves quickly once the ambiguity clears','that burns off as soon as the first concrete step is taken','that leaves only a faint watchfulness behind']::text[] AS cl_mid,
  ARRAY['righteous anger','appeasement','defiant doubling','vindication seeking','aggressive counter','fomo buying']::text[] AS pa_mid,
  ARRAY['Barely a ripple of concern','Almost no visible reaction at all','A flat, measured pulse with no real spike','The faintest tightening, gone as soon as it is noticed','Something closer to mild interest than alarm','A slight narrowing of attention, nothing more','The emotional equivalent of a raised eyebrow']::text[] AS op_low,
  ARRAY['that resolves almost before it registers','that is essentially forgotten by the next decision','that leaves no discernible trace once the moment passes','that never really rises to the level of a feeling at all','that reads on the outside as nothing having happened','that is filed away before it finishes arriving']::text[] AS cl_low,
  ARRAY['cold calculation','stoic freeze','performative calm','euphoric overreach','relief capitulation']::text[] AS pa_low
) b
WHERE p.id = r.profile_id AND s.id = r.scenario_id
  AND r.id IN (SELECT id FROM _v4_backup_responses_v3)
  AND (r.reasoning_chain LIKE '%loss aversion coefficient%'
       OR r.response ~ '^(BUY|ADD|HOLD|TRIM|SELL|CUT) — '
       OR r.emotional_arc IS NULL);

-- provenance for repaired responses -------------------------------------------
INSERT INTO provenance (entity_type, entity_id, entity_version, model, prompt_hash, template_hash, params, sha256_content)
SELECT 'profile_scenario_response', r.id, 1, 'authored/psychosynth-synth-v4-repair',
       encode(sha256(convert_to('v4-response-repair:' || r.id::text, 'UTF8')), 'hex'),
       'ed1acd9762eeac5102b1c8cfcdbc3ea44ca5bed673cf1286568618953acce34f',
       jsonb_build_object('method','sql-authored-repair','source','v3-template-batch'),
       encode(sha256(convert_to(r.response || '|' || r.reasoning_chain, 'UTF8')), 'hex')
FROM profile_scenario_responses r
WHERE r.id IN (SELECT id FROM _v4_backup_responses_v3)
  AND NOT EXISTS (SELECT 1 FROM provenance pr
                  WHERE pr.entity_type='profile_scenario_response' AND pr.entity_id=r.id
                    AND pr.model='authored/psychosynth-synth-v4-repair')
ON CONFLICT (entity_type, entity_id, entity_version) DO NOTHING;
